   201→    /// 僅讀 metadata 取得尺寸（不解碼，portrait fit-to-width 時避免 thumbnail→fullRes 跳動）
   202→    private static func readImageDimensions(at url: URL) -> CGSize? {
   203→        guard !isPDFURL(url) else { return nil }
   204→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil) else { return nil }
   205→        guard let props = CGImageSourceCopyPropertiesAtIndex(source, 0, nil) as NSDictionary? else { return nil }
   206→        let w = (props[kCGImagePropertyPixelWidth] as? NSNumber)?.intValue ?? 0
   207→        let h = (props[kCGImagePropertyPixelHeight] as? NSNumber)?.intValue ?? 0
   208→        guard w > 0, h > 0 else { return nil }
   209→        return CGSize(width: w, height: h)
   210→    }
   211→
   212→    /// 使用 CGImageSourceCreateThumbnailAtIndex 快速解碼縮圖，同時讀取 full-res 尺寸
   213→    /// 共用同一個 CGImageSource，避免二次開檔
   214→    private static func decodeThumbnailWithDimensions(at url: URL, maxSize: CGFloat) -> (image: NSImage, fullSize: CGSize)? {
   215→        guard !isPDFURL(url) else { return nil }
   216→        let decodeStart = CFAbsoluteTimeGetCurrent()
   217→
   218→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil) else { return nil }
   219→        let sourceMs = (CFAbsoluteTimeGetCurrent() - decodeStart) * 1000
   220→
   221→        // 讀 full-res dimensions（同一個 source，零額外 I/O）
   222→        let fullSize: CGSize
   223→        if let props = CGImageSourceCopyPropertiesAtIndex(source, 0, nil) as NSDictionary?,
   224→           let w = (props[kCGImagePropertyPixelWidth] as? NSNumber)?.intValue,
   225→           let h = (props[kCGImagePropertyPixelHeight] as? NSNumber)?.intValue,
   226→           w > 0, h > 0 {
   227→            fullSize = CGSize(width: w, height: h)
   228→        } else {
   229→            fullSize = .zero  // fallback: caller 會用 thumbnail size
   230→        }
   231→
   232→        var options: [CFString: Any] = [
   233→            kCGImageSourceCreateThumbnailFromImageAlways: true,
   234→            kCGImageSourceCreateThumbnailWithTransform: true,
   235→            kCGImageSourceThumbnailMaxPixelSize: maxSize,
   236→        ]
   237→        // Phase 3.1: SubsampleFactor for JPEG/HEIF DCT fast path at micro-thumbnail sizes
   238→        let subsample: Int
   239→        if maxSize <= Constants.quickGridSubsampleThresholdPx {
   240→            subsample = 4
   241→            options[kCGImageSourceSubsampleFactor] = subsample
   242→        } else {
   243→            subsample = 1
   244→        }
   245→        let thumbStart = CFAbsoluteTimeGetCurrent()
   246→        guard let cgImage = CGImageSourceCreateThumbnailAtIndex(source, 0, options as CFDictionary)
   247→        else { return nil }
   248→        let thumbMs = (CFAbsoluteTimeGetCurrent() - thumbStart) * 1000
   249→
   250→        let image = NSImage(cgImage: cgImage, size: NSSize(
   251→            width: cgImage.width,
   252→            height: cgImage.height
   253→        ))
   254→        let totalMs = (CFAbsoluteTimeGetCurrent() - decodeStart) * 1000
   255→        GridPerfLog.log(String(format: "decode: total=%.2fms | source=%.2fms | thumb(%dx%d→%.0f,ss=%d)=%.2fms | %@",
   256→                               totalMs, sourceMs, cgImage.width, cgImage.height, maxSize, subsample, thumbMs,
   257→                               url.lastPathComponent))
   258→
   259→        let effectiveSize = fullSize == .zero ? image.size : fullSize
   260→        return (image, effectiveSize)
   261→    }
