   263→    /// 使用 ImageIO 高效解碼（比 NSImage(contentsOf:) 更高效）
   264→    private static func decodeImage(at url: URL) -> NSImage? {
   265→        guard let source = CGImageSourceCreateWithURL(url as CFURL, nil) else { return nil }
   266→        let options: [CFString: Any] = [
   267→            kCGImageSourceShouldCache: true,
   268→            kCGImageSourceShouldAllowFloat: true
   269→        ]
   270→        guard let cgImage = CGImageSourceCreateImageAtIndex(source, 0, options as CFDictionary)
   271→        else { return nil }
   272→        return NSImage(cgImage: cgImage, size: NSSize(
   273→            width: cgImage.width,
   274→            height: cgImage.height
   275→        ))
   276→    }
