   278→    /// 預載用的圖片載入（支援 cooperative cancellation）
   279→    private func loadImageCooperative(at url: URL) async -> NSImage? {
   280→        if let cached = cache[url] { return cached }
   281→        guard !Task.isCancelled else { return nil }
   282→
   283→        // 使用 Task 而非 Task.detached 以繼承 cancellation scope
   284→        let image = await Task(priority: .userInitiated) { () -> NSImage? in
   285→            guard !Task.isCancelled else { return nil }
   286→            return Self.decodeImage(at: url)
   287→        }.value
   288→
   289→        guard !Task.isCancelled else { return nil }
   290→        if let image { cache[url] = image }
   291→        return image
   292→    }
