   294→    /// 取消指定 item 的預載任務
   295→    func cancelLoad(for item: ImageItem) {
   296→        if let pageIndex = item.pdfPageIndex {
   297→            let key = PDFCacheKey(url: item.url, pageIndex: pageIndex)
   298→            prefetchTasks[key]?.cancel()
   299→            prefetchTasks.removeValue(forKey: key)
   300→        } else {
   301→            imagePrefetchTasks[item.url]?.cancel()
   302→            imagePrefetchTasks.removeValue(forKey: item.url)
   303→        }
   304→    }
   305→
   306→    /// 預載周圍項目（圖片或 PDF 頁面），釋放遠離的快取
   307→    /// 方向性 prefetch：往 direction 方向多預載 prefetchExtra 張
   308→    /// ⚠️ 接收值型別參數（ImageItem 是 Sendable struct）避免 Swift 6 Sendable 問題
   309→    func updateCache(currentIndex: Int, items: [ImageItem], prefetchDirection: PrefetchDirection = .none) {
   310→        guard !items.isEmpty else { return }
   311→
   312→        let range: ClosedRange<Int>
   313→        switch prefetchDirection {
   314→        case .forward:
   315→            range = max(0, currentIndex - cacheRadius)...min(items.count - 1, currentIndex + cacheRadius + prefetchExtra)
   316→        case .backward:
   317→            range = max(0, currentIndex - cacheRadius - prefetchExtra)...min(items.count - 1, currentIndex + cacheRadius)
   318→        case .none:
   319→            range = max(0, currentIndex - cacheRadius)...min(items.count - 1, currentIndex + cacheRadius)
   320→        }
   321→
   322→        // 計算需要的 keys
   323→        let activeImageURLs = Set(items[range].filter { !$0.isPDF }.map(\.url))
   324→        let activePDFKeys = Set(items[range].compactMap { item in
   325→            item.pdfPageIndex.map { PDFCacheKey(url: item.url, pageIndex: $0) }
   326→        })
   327→        let activePDFURLs = Set(items[range].filter { $0.isPDF }.map(\.url))
   328→
   329→        // 取消不在範圍內的預載任務
   330→        for (url, task) in imagePrefetchTasks where !activeImageURLs.contains(url) {
   331→            task.cancel()
   332→            imagePrefetchTasks.removeValue(forKey: url)
   333→        }
   334→        for (key, task) in prefetchTasks where !activePDFKeys.contains(key) {
   335→            task.cancel()
   336→            prefetchTasks.removeValue(forKey: key)
   337→        }
   338→
   339→        // 釋放超出範圍的快取
   340→        cache = cache.filter { activeImageURLs.contains($0.key) }
   341→        thumbnailCache = thumbnailCache.filter { activeImageURLs.contains($0.key.url) }
   342→        pdfCache = pdfCache.filter { activePDFKeys.contains($0.key) }
   343→        pdfDocumentCache = pdfDocumentCache.filter { activePDFURLs.contains($0.key) }
   344→
   345→        // 啟動新的預載任務（可追蹤、可取消）
   346→        for i in range {
   347→            let item = items[i]
   348→            if let pageIndex = item.pdfPageIndex {
   349→                let key = PDFCacheKey(url: item.url, pageIndex: pageIndex)
   350→                if pdfCache[key] == nil && prefetchTasks[key] == nil {
   351→                    prefetchTasks[key] = Task {
   352→                        defer { prefetchTasks.removeValue(forKey: key) }
   353→                        guard !Task.isCancelled else { return }
   354→                        _ = await loadPDFPage(url: item.url, pageIndex: pageIndex)
   355→                    }
   356→                }
   357→            } else {
   358→                if cache[item.url] == nil && imagePrefetchTasks[item.url] == nil {
   359→                    imagePrefetchTasks[item.url] = Task {
   360→                        defer { imagePrefetchTasks.removeValue(forKey: item.url) }
   361→                        guard !Task.isCancelled else { return }
   362→                        _ = await loadImageCooperative(at: item.url)
   363→                    }
   364→                }
   365→            }
   366→        }
   367→    }
   368→
   369→    /// 清空縮圖快取（Quick Grid dismiss 後呼叫，避免 240px 小圖殘留污染主畫面 fallback）
   370→    func clearThumbnailCache() {
   371→        thumbnailCache.removeAll()
   372→    }
   373→
   374→    /// 取消所有預載任務並清空縮圖快取
   375→    func cancelAllPrefetchTasks() {
   376→        for (_, task) in prefetchTasks { task.cancel() }
   377→        for (_, task) in imagePrefetchTasks { task.cancel() }
   378→        prefetchTasks.removeAll()
   379→        imagePrefetchTasks.removeAll()
   380→        thumbnailCache.removeAll()
   381→    }
   382→}
