   649→    private func updateDragHighlightPath() {
   650→        let inset: CGFloat = 8
   651→        // Asymmetric inset: extra bottom space to avoid status bar overlay
   652→        let topInset = inset
   653→        let bottomInset = inset + dragBottomInset
   654→        let rect = CGRect(
   655→            x: bounds.minX + inset,
   656→            y: bounds.minY + topInset,
   657→            width: bounds.width - inset * 2,
   658→            height: bounds.height - topInset - bottomInset
   659→        )
   660→        dragHighlightLayer.frame = bounds
   661→        dragHighlightLayer.path = CGPath(
   662→            roundedRect: rect,
   663→            cornerWidth: 8,
   664→            cornerHeight: 8,
