   671→    /// 邊緣按鍵計數器：到邊緣後需連續按 N 次同方向才觸發翻頁
   672→    /// threshold 可覆蓋預設值（PageUp/PageDown 只需 1 次確認）
   673→    private func handleEdgePress(keyCode: UInt16, threshold: Int? = nil, navigateAction: () -> Void) {
   674→        if keyCode == edgePressDirection {
   675→            edgePressCount += 1
   676→        } else {
   677→            // 方向改變：先隱藏舊 indicator 再重置
   678→            resetEdgeState()
   679→            edgePressDirection = keyCode
   680→            edgePressCount = 1
   681→        }
   682→        let effectiveThreshold = threshold ?? edgePressThreshold
   683→        let progress = CGFloat(edgePressCount) / CGFloat(effectiveThreshold)
   684→        let edge = edgeForKeyCode(keyCode)
   685→        showEdgeIndicator(edge: edge, progress: progress)
   686→        if edgePressCount >= effectiveThreshold {
   687→            edgePressCount = 0
   688→            edgePressDirection = 0
   689→            hideEdgeIndicators()
   690→            navigateAction()
   691→        }
   692→    }
