   412→    // MARK: - Viewport Overflow Detection
   413→
   414→    /// 判斷圖片（含 magnification）是否超出 viewport 各軸
   415→    private var viewportOverflow: (horizontal: Bool, vertical: Bool) {
   416→        guard let docView = documentView else { return (false, false) }
   417→        let clipSize = contentView.bounds.size
   418→        let docSize = docView.frame.size
   419→        let eps: CGFloat = 1.0
   420→        return (
   421→            horizontal: docSize.width > clipSize.width + eps,
   422→            vertical: docSize.height > clipSize.height + eps
   423→        )
   424→    }
