   426→    // MARK: - Programmatic Pan
   427→
   428→    private var scrollDebounceWorkItem: DispatchWorkItem?
   429→
   430→    /// Y 軸的 scroll 範圍（考慮 contentInsets）
   431→    /// NSScrollView contentInsets 以視覺邊緣為語意：.bottom = visual bottom (minY), .top = visual top (maxY)
   432→    private func yScrollBounds(docHeight: CGFloat, clipHeight: CGFloat, insets: NSEdgeInsets) -> (min: CGFloat, max: CGFloat) {
   433→        let minY = -insets.bottom
   434→        let maxY = max(docHeight - clipHeight + insets.top, minY)
   435→        return (min: minY, max: maxY)
   436→    }
   437→
   438→    private func panLeft() {
   439→        let clip = contentView
   440→        let insets = contentInsets
   441→        let minX = -insets.left
   442→        let newX = max(clip.bounds.minX - Constants.arrowPanStep, minX)
   443→        animateScroll(to: NSPoint(x: newX, y: clip.bounds.minY))
   444→    }
   445→
   446→    private func panRight() {
   447→        let clip = contentView
   448→        guard let docView = documentView else { return }
   449→        let insets = contentInsets
   450→        let maxX = max(docView.frame.width - clip.bounds.width + insets.right, -insets.left)
   451→        let newX = min(clip.bounds.minX + Constants.arrowPanStep, maxX)
   452→        animateScroll(to: NSPoint(x: newX, y: clip.bounds.minY))
   453→    }
   454→
   455→    /// macOS unflipped: visual up = increase Y
   456→    private func panUp() {
   457→        let clip = contentView
   458→        guard let docView = documentView else { return }
   459→        let yBounds = yScrollBounds(docHeight: docView.frame.height, clipHeight: clip.bounds.height, insets: contentInsets)
   460→        let newY = min(clip.bounds.minY + Constants.arrowPanStep, yBounds.max)
   461→        animateScroll(to: NSPoint(x: clip.bounds.minX, y: newY))
   462→    }
   463→
   464→    /// macOS unflipped: visual down = decrease Y
   465→    private func panDown() {
   466→        let clip = contentView
   467→        let yBounds = yScrollBounds(docHeight: documentView?.frame.height ?? 0, clipHeight: clip.bounds.height, insets: contentInsets)
   468→        let newY = max(clip.bounds.minY - Constants.arrowPanStep, yBounds.min)
   469→        animateScroll(to: NSPoint(x: clip.bounds.minX, y: newY))
   470→    }
   471→
   472→    /// Animated scroll helper with debounced completion
   473→    /// Uses debounce to prevent stuttering when key repeat triggers rapid successive animations
   474→    private func animateScroll(to newOrigin: NSPoint) {
   475→        let clip = contentView
   476→
   477→        // Cancel previous debounce timer
   478→        scrollDebounceWorkItem?.cancel()
   479→
   480→        NSAnimationContext.runAnimationGroup { context in
   481→            context.duration = Constants.arrowPanAnimationDuration
   482→            context.timingFunction = CAMediaTimingFunction(name: .linear)
   483→            context.allowsImplicitAnimation = true
   484→            clip.scroll(to: newOrigin)
   485→        }
   486→
   487→        // Debounce: only sync scrollbars after animations settle
   488→        let workItem = DispatchWorkItem { [weak self] in
   489→            guard let self else { return }
   490→            self.reflectScrolledClipView(clip)
   491→        }
   492→        scrollDebounceWorkItem = workItem
   493→        let debounceDelay = Constants.arrowPanAnimationDuration + 0.05  // padding after animation settles
   494→        DispatchQueue.main.asyncAfter(
   495→            deadline: .now() + debounceDelay,
   496→            execute: workItem
   497→        )
   498→    }
