   500→    // MARK: - Edge Indicator (翻頁進度視覺提示)
   501→
   502→    private static let indicatorThickness: CGFloat = 20
   503→
   504→    private func makeEdgeIndicator(edge: Edge) -> CAGradientLayer {
   505→        let layer = CAGradientLayer()
   506→        layer.opacity = 0
   507→        layer.isHidden = true
   508→        layer.zPosition = 1000  // 浮在 NSScrollView 內部 clip view 之上
   509→        // #F97068 coral accent
   510→        let accent = NSColor(red: 249/255.0, green: 112/255.0, blue: 104/255.0, alpha: 0.9).cgColor
   511→        let clear = NSColor.clear.cgColor
   512→        // AppKit layer-backed: y=0 是視覺頂部（flipped）
   513→        // 每條 indicator 的漸層方向：邊緣實色 → 內部透明
   514→        switch edge {
   515→        case .top:
   516→            layer.colors = [accent, clear]
   517→            layer.startPoint = CGPoint(x: 0.5, y: 0)  // 頂部邊緣
   518→            layer.endPoint = CGPoint(x: 0.5, y: 1)    // 向內淡出
   519→        case .bottom:
   520→            layer.colors = [clear, accent]
   521→            layer.startPoint = CGPoint(x: 0.5, y: 0)  // 內部
   522→            layer.endPoint = CGPoint(x: 0.5, y: 1)    // 底部邊緣
   523→        case .left:
   524→            layer.colors = [accent, clear]
   525→            layer.startPoint = CGPoint(x: 0, y: 0.5)  // 左邊緣
   526→            layer.endPoint = CGPoint(x: 1, y: 0.5)    // 向內淡出
   527→        case .right:
   528→            layer.colors = [clear, accent]
   529→            layer.startPoint = CGPoint(x: 0, y: 0.5)  // 內部
   530→            layer.endPoint = CGPoint(x: 1, y: 0.5)    // 右邊緣
   531→        }
   532→        return layer
   533→    }
   534→
   535→    private func ensureIndicatorsAttached() {
   536→        // wantsLayer 保證 self.layer 存在
   537→        wantsLayer = true
   538→        guard let root = layer else { return }
   539→        for indicator in [topIndicator, bottomIndicator, leftIndicator, rightIndicator] {
   540→            if indicator.superlayer == nil {
   541→                root.addSublayer(indicator)
   542→            }
   543→        }
   544→    }
   545→
   546→    private func edgeForKeyCode(_ keyCode: UInt16) -> Edge {
   547→        switch keyCode {
   548→        case 125, 49, 121: return .bottom  // ↓, Space, PageDown
   549→        case 126, 116:     return .top     // ↑, PageUp
   550→        case 124:          return .right   // →
   551→        case 123:          return .left    // ←
   552→        default:           return .bottom
   553→        }
   554→    }
   555→
   556→    private func indicatorLayer(for edge: Edge) -> CAGradientLayer {
   557→        switch edge {
   558→        case .top:    return topIndicator
   559→        case .bottom: return bottomIndicator
   560→        case .left:   return leftIndicator
   561→        case .right:  return rightIndicator
   562→        }
   563→    }
   564→
   565→    private func showEdgeIndicator(edge: Edge, progress: CGFloat) {
   566→        ensureIndicatorsAttached()
   567→        layoutEdgeIndicators()
   568→        let layer = indicatorLayer(for: edge)
   569→        layer.isHidden = false
   570→        CATransaction.begin()
   571→        CATransaction.setAnimationDuration(0.1)
   572→        layer.opacity = Float(min(progress, 1.0))
   573→        CATransaction.commit()
   574→        scheduleIndicatorFadeOut()
   575→    }
   576→
   577→    /// 排程自動淡出：每次 edge press 重置計時器，閒置 1.5 秒後淡出
   578→    private func scheduleIndicatorFadeOut() {
   579→        edgeIndicatorFadeTimer?.cancel()
   580→        let task = DispatchWorkItem { [weak self] in
   581→            self?.resetEdgeState()
   582→        }
   583→        edgeIndicatorFadeTimer = task
   584→        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5, execute: task)
   585→    }
   586→
   587→    /// 重置所有邊緣狀態：隱藏 indicator + 清除計數
   588→    func resetEdgeState() {
   589→        edgeIndicatorFadeTimer?.cancel()
   590→        edgeIndicatorFadeTimer = nil
   591→        edgePressCount = 0
   592→        edgePressDirection = 0
   593→        for indicator in [topIndicator, bottomIndicator, leftIndicator, rightIndicator] {
   594→            guard !indicator.isHidden else { continue }
   595→            CATransaction.begin()
   596→            CATransaction.setAnimationDuration(0.3)
   597→            indicator.opacity = 0
   598→            CATransaction.commit()
   599→            DispatchQueue.main.asyncAfter(deadline: .now() + 0.3) {
   600→                indicator.isHidden = true
   601→            }
   602→        }
   603→    }
   604→
   605→    private func hideEdgeIndicators() {
   606→        resetEdgeState()
   607→    }
   608→
   609→    private func layoutEdgeIndicators() {
   610→        let t = Self.indicatorThickness
   611→        let b = bounds
   612→        // AppKit layer-backed: y=0 是視覺頂部（flipped）
   613→        topIndicator.frame = CGRect(x: 0, y: 0, width: b.width, height: t)
   614→        bottomIndicator.frame = CGRect(x: 0, y: b.height - t - dragBottomInset, width: b.width, height: t)
   615→        leftIndicator.frame = CGRect(x: 0, y: 0, width: t, height: b.height)
   616→        rightIndicator.frame = CGRect(x: b.width - t, y: 0, width: t, height: b.height)
   617→    }
