   628→    // MARK: - Drag Highlight (Phase 2: Visual Feedback)
   629→
   630→    private func updateDragHighlight() {
   631→        ensureDragHighlightAttached()
   632→        updateDragHighlightPath()
   633→
   634→        NSAnimationContext.runAnimationGroup { context in
   635→            context.duration = 0.15
   636→            context.allowsImplicitAnimation = true
   637→            dragHighlightLayer.isHidden = !isDragOver
