   643→    private func ensureDragHighlightAttached() {
   644→        wantsLayer = true
   645→        guard let root = layer, dragHighlightLayer.superlayer == nil else { return }
   646→        root.addSublayer(dragHighlightLayer)  // Lazy attachment on first drag
