   694→    // MARK: - Keyboard (first responder)
   695→
   696→    override var acceptsFirstResponder: Bool { true }
   697→
   698→    /// 鍵盤事件在此攔截，避免 NSScrollView 內部消化方向鍵/Space/PageUp/PageDown
   699→    /// 方向鍵根據 viewport overflow 動態切換 pan 或 navigate
   700→    /// 到邊緣時需連續按 N 次才翻頁，防止瀏覽長圖時誤觸
   701→    override func keyDown(with event: NSEvent) {
   702→        let overflow = viewportOverflow
   703→        let navAmount = event.modifierFlags.contains(.option) ? Constants.optionKeyJumpAmount : 1
   704→
   705→        switch event.keyCode {
   706→        case 124: // → RightArrow
   707→            let rightAction: () -> Void = { [weak self] in
   708→                guard let self else { return }
   709→                if self.isRTLNavigation {
   710→                    self.scrollDelegate?.scrollViewRequestPreviousImage(self, amount: navAmount)
   711→                } else {
   712→                    self.scrollDelegate?.scrollViewRequestNextImage(self, amount: navAmount)
   713→                }
   714→            }
   715→            if overflow.horizontal {
   716→                if !isAtRight {
   717→                    panRight()
   718→                    edgePressCount = 0
   719→                    hideEdgeIndicators()
   720→                } else if arrowLeftRightNavigation {
   721→                    handleEdgePress(keyCode: 124, navigateAction: rightAction)
   722→                }
   723→            } else if arrowLeftRightNavigation {
   724→                resetEdgeState()
   725→                rightAction()
   726→            }
   727→
   728→        case 123: // ← LeftArrow
   729→            let leftAction: () -> Void = { [weak self] in
   730→                guard let self else { return }
   731→                if self.isRTLNavigation {
   732→                    self.scrollDelegate?.scrollViewRequestNextImage(self, amount: navAmount)
   733→                } else {
   734→                    self.scrollDelegate?.scrollViewRequestPreviousImage(self, amount: navAmount)
   735→                }
   736→            }
   737→            if overflow.horizontal {
   738→                if !isAtLeft {
   739→                    panLeft()
   740→                    edgePressCount = 0
   741→                    hideEdgeIndicators()
   742→                } else if arrowLeftRightNavigation {
   743→                    handleEdgePress(keyCode: 123, navigateAction: leftAction)
   744→                }
   745→            } else if arrowLeftRightNavigation {
   746→                resetEdgeState()
   747→                leftAction()
   748→            }
   749→
   750→        case 125: // ↓ DownArrow
   751→            if overflow.vertical && !isAtBottom {
   752→                panDown()
   753→                edgePressCount = 0
   754→                hideEdgeIndicators()
   755→            } else if arrowUpDownNavigation {
   756→                if overflow.vertical {
   757→                    // At bottom edge: edge-press to navigate
   758→                    handleEdgePress(keyCode: 125) { [weak self] in
   759→                        guard let self else { return }
   760→                        self.scrollDelegate?.scrollViewRequestNextImage(self, amount: navAmount)
   761→                    }
   762→                } else {
   763→                    // No vertical overflow: navigate directly
   764→                    resetEdgeState()
   765→                    scrollDelegate?.scrollViewRequestNextImage(self, amount: navAmount)
   766→                }
   767→            }
   768→
   769→        case 126: // ↑ UpArrow
   770→            if overflow.vertical && !isAtTop {
   771→                panUp()
   772→                edgePressCount = 0
   773→                hideEdgeIndicators()
   774→            } else if arrowUpDownNavigation {
   775→                if overflow.vertical {
   776→                    // At top edge: edge-press to navigate
   777→                    handleEdgePress(keyCode: 126) { [weak self] in
   778→                        guard let self else { return }
   779→                        self.scrollDelegate?.scrollViewRequestPreviousImage(self, amount: navAmount)
   780→                    }
   781→                } else {
   782→                    // No vertical overflow: navigate directly
   783→                    resetEdgeState()
   784→                    scrollDelegate?.scrollViewRequestPreviousImage(self, amount: navAmount)
   785→                }
   786→            }
   787→
   788→        case 49, 121: // Space / PageDown
   789→            if overflow.vertical && isAtBottom {
   790→                handleEdgePress(keyCode: event.keyCode, threshold: 1) { [weak self] in
   791→                    guard let self else { return }
   792→                    scrollDelegate?.scrollViewRequestPageDown(self)
   793→                }
   794→            } else {
   795→                edgePressCount = 0
   796→                hideEdgeIndicators()
   797→                scrollDelegate?.scrollViewRequestPageDown(self)
   798→            }
   799→
   800→        case 116: // PageUp
   801→            if overflow.vertical && isAtTop {
   802→                handleEdgePress(keyCode: 116, threshold: 1) { [weak self] in
   803→                    guard let self else { return }
   804→                    scrollDelegate?.scrollViewRequestPageUp(self)
   805→                }
   806→            } else {
   807→                edgePressCount = 0
   808→                hideEdgeIndicators()
   809→                scrollDelegate?.scrollViewRequestPageUp(self)
   810→            }
   811→
   812→        case 115: scrollDelegate?.scrollViewRequestFirstImage(self)     // Home
   813→        case 119: scrollDelegate?.scrollViewRequestLastImage(self)      // End
   814→        case 5 where event.modifierFlags.intersection(.deviceIndependentFlagsMask) == []:  // bare G (no modifiers)
   815→            scrollDelegate?.scrollViewRequestToggleQuickGrid(self)
   816→        case 53:  // Esc — 退出全螢幕（僅在全螢幕模式下有效）
   817→            if window?.styleMask.contains(.fullScreen) == true {
   818→                window?.toggleFullScreen(nil)
   819→            } else {
   820→                super.keyDown(with: event)
   821→            }
   822→        default:  super.keyDown(with: event)
   823→        }
   824→    }
