   864→    /// macOS unflipped: visual bottom = minY ≈ 0, scroll down = decrease Y
   865→    private func scrollPageDownOrNext() {
   866→        let clipView = scrollView.contentView
   867→        let visibleHeight = clipView.bounds.height
   868→        let currentMinY = clipView.bounds.minY
   869→
   870→        // Visual bottom in unflipped coords = minY near 0
   871→        if currentMinY <= Constants.scrollEdgeThreshold {
   872→            goToNextImage()
   873→        } else {
   874→            let newY = max(currentMinY - visibleHeight, 0)
   875→            clipView.scroll(to: NSPoint(x: clipView.bounds.minX, y: newY))
   876→            scrollView.reflectScrolledClipView(clipView)
   877→        }
   878→    }
