   880→    /// PageUp：視覺向上捲動一頁，到頂部則翻到上一張
   881→    /// macOS unflipped: visual top = maxY ≈ docHeight, scroll up = increase Y
   882→    private func scrollPageUpOrPrev() {
   883→        let clipView = scrollView.contentView
   884→        let visibleHeight = clipView.bounds.height
   885→        let currentMinY = clipView.bounds.minY
   886→        let docHeight = scrollView.documentView?.frame.height ?? 0
   887→
   888→        // Visual top in unflipped coords = maxY near docHeight
   889→        let clipMaxY = currentMinY + visibleHeight
   890→        if clipMaxY >= docHeight - Constants.scrollEdgeThreshold {
   891→            goToPreviousImage()
   892→        } else {
   893→            let newY = min(currentMinY + visibleHeight, docHeight - visibleHeight)
   894→            clipView.scroll(to: NSPoint(x: clipView.bounds.minX, y: newY))
   895→            scrollView.reflectScrolledClipView(clipView)
   896→        }
   897→    }
