    92→    // MARK: - Subfolder Discovery
    93→
    94→    /// BFS search for the first subdirectory that contains supported images.
    95→    /// - Parameters:
    96→    ///   - rootURL: The folder to start searching from (its direct children are depth 1).
    97→    ///   - maxDepth: Maximum depth to search (e.g. 2 means grandchildren at most).
    98→    /// - Returns: The URL of the first subfolder containing images, or nil.
    99→    static func findFirstSubfolderWithImages(in rootURL: URL, maxDepth: Int) -> URL? {
   100→        let fm = FileManager.default
   101→        var queue: [(url: URL, depth: Int)] = []
   102→
   103→        // Seed queue with immediate subdirectories (depth 1)
   104→        let (_, rootSubdirs) = scanFolderContents(rootURL, using: fm)
   105→        for child in rootSubdirs {
   106→            queue.append((child, 1))
   107→        }
   108→
   109→        while !queue.isEmpty {
   110→            let (currentURL, depth) = queue.removeFirst()
   111→
   112→            let (hasImages, subdirs) = scanFolderContents(currentURL, using: fm)
   113→            if hasImages {
   114→                return currentURL
   115→            }
   116→
   117→            // Enqueue deeper subdirectories if within depth limit
   118→            if depth < maxDepth {
   119→                for child in subdirs {
   120→                    queue.append((child, depth + 1))
   121→                }
   122→            }
   123→        }
   124→
   125→        return nil
   126→    }
