   128→    /// Single-pass scan: checks for supported images AND collects sorted subdirectories.
   129→    /// Reads directory contents once with all needed resource keys to avoid redundant I/O.
   130→    private static func scanFolderContents(_ url: URL, using fm: FileManager) -> (hasImages: Bool, subdirs: [URL]) {
   131→        guard let contents = try? fm.contentsOfDirectory(
   132→            at: url,
   133→            includingPropertiesForKeys: [.isDirectoryKey, .isPackageKey, .contentTypeKey],
   134→            options: .skipsHiddenFiles
   135→        ) else { return (false, []) }
   136→
   137→        var subdirs: [URL] = []
   138→
   139→        for child in contents {
   140→            guard let values = try? child.resourceValues(
   141→                forKeys: [.isDirectoryKey, .isPackageKey, .contentTypeKey]
   142→            ) else { continue }
   143→
   144→            if values.isDirectory == true && values.isPackage != true {
   145→                subdirs.append(child)
   146→            } else if let type = values.contentType,
   147→                      supportedTypes.contains(where: { type.conforms(to: $0) }) {
   148→                return (true, [])  // Short-circuit: caller ignores subdirs when hasImages
   149→            }
   150→        }
   151→
   152→        subdirs.sort { $0.lastPathComponent.localizedStandardCompare($1.lastPathComponent) == .orderedAscending }
   153→        return (false, subdirs)
   154→    }
