   156→    /// 輕量取 PDF 頁數：Spotlight 元資料 → CGPDFDocument → 0
   157→    private static func pdfPageCount(for url: URL) -> Int {
   158→        if let mdItem = MDItemCreateWithURL(nil, url as CFURL),
   159→           let pages = MDItemCopyAttribute(mdItem, kMDItemNumberOfPages) as? Int,
   160→           pages > 0 {
   161→            return pages
   162→        }
   163→        if let cgDoc = CGPDFDocument(url as CFURL) {
   164→            return cgDoc.numberOfPages
   165→        }
   166→        return 0
   167→    }
