#### 3.1 核心結構

```swift
class ContinuousScrollContentView: NSView {
    // View Recycling Pool
    private var reusableSlots: [ImageSlotView] = []
    private var activeSlots: [Int: ImageSlotView] = [:]  // index -> slot

    // 佈局資訊
    private var imageSizes: [NSSize] = []  // pre-scanned sizes
    private var imageYOffsets: [CGFloat] = []  // 每張圖的 Y 起始位置
    private var totalHeight: CGFloat = 0

